import{_ as o,C as t,o as n,c as i,a4 as l,E as s}from"./chunks/framework.BjA-8Gni.js";const k=JSON.parse('{"title":"Amiga clock","description":"A desktop of live animated clocks — analog, digital, and the bouncing Amiga boing ball — a runnable JSVision example in the browser.","frontmatter":{"title":"Amiga clock","description":"A desktop of live animated clocks — analog, digital, and the bouncing Amiga boing ball — a runnable JSVision example in the browser."},"headers":[],"relativePath":"apps/amiga-clock.md","filePath":"apps/amiga-clock.md"}'),r={name:"apps/amiga-clock.md"};function c(g,a,d,m,p,h){const e=t("PlayExample");return n(),i("div",null,[a[0]||(a[0]=l('<h1 id="amiga-clock" tabindex="-1">Amiga clock <a class="header-anchor" href="#amiga-clock" aria-label="Permalink to &quot;Amiga clock&quot;">​</a></h1><p>A little desktop of clocks, all live: an analog Workbench-style face, a big block-glyph digital readout with a blinking colon, the bouncing Amiga <strong>boing</strong> ball with the time overlaid, and a fourth window that nests all three in a draggable split grid. Every window moves, resizes, zooms, and closes like any other — the standard windowing shell, running unchanged in the browser.</p><p>A single ~12 fps timer drives two signals — a frame counter for the spin and bounce, and the current time — and the reactive views bound to them repaint themselves; nothing redraws by hand. Drag a title bar to move a window, drag a corner to resize, <strong>F2</strong> to zoom, <strong>F4</strong> / <strong>F5</strong> to tile / cascade, <strong>F6</strong> for the next window, and <strong>Tab</strong> to cycle focus.</p>',3)),s(e,{id:"apps/amiga-clock",title:"Amiga clock",blurb:"A desktop of live clocks — analog, digital, and the bouncing Amiga boing ball — each in its own window."})])}const u=o(r,[["render",c]]);export{k as __pageData,u as default};
